from typing import List

class Solution:
    def isGood(self, nums: List[int]) -> bool:
        n = max(nums)
        # base[n] has length n + 1
        if len(nums) != n + 1:
            return False

        # base[n] contains 1..n-1 exactly once and n exactly twice
        freq = [0] * (n + 1)
        for x in nums:
            if x < 1 or x > n:
                return False
            freq[x] += 1

        # Check counts for 1..n-1 and n
        for v in range(1, n):
            if freq[v] != 1:
                return False
        return freq[n] == 2
```

